import{_ as t,o,c as a,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"zkqes CLI release pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"install/zkqes-cli.md","filePath":"cli-release.md","lastUpdated":1777988338000}'),d={name:"install/zkqes-cli.md"};function s(i,e,c,l,n,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="zkqes-cli-release-pipeline" tabindex="-1"><code>zkqes</code> CLI release pipeline <a class="header-anchor" href="#zkqes-cli-release-pipeline" aria-label="Permalink to &quot;`zkqes` CLI release pipeline&quot;">​</a></h1><blockquote><p><strong>Renamed 2026-05-03</strong> — see <a href="./2026-05-03-zkqes-rename-design"><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code></a> for the rename baseline. Historical references to QKB/QIE/Identity-Escrow in pre-2026-05-03 commits remain immutable in git history.</p></blockquote><p>This document describes the secrets and external resources the <code>.github/workflows/release-cli.yml</code> workflow needs in order to ship a signed, multi-platform release of the <code>zkqes</code> CLI.</p><h2 id="tag-→-release-flow" tabindex="-1">Tag → release flow <a class="header-anchor" href="#tag-→-release-flow" aria-label="Permalink to &quot;Tag → release flow&quot;">​</a></h2><ol><li>Bump <code>packages/zkqes-cli/package.json</code> <code>version</code> and commit on a release branch.</li><li>Tag the commit <code>cli-v&lt;X.Y.Z&gt;</code> (e.g. <code>cli-v0.1.0</code>).</li><li>Push the tag — the workflow builds 5 binaries via <code>bun build --compile</code>, signs the macOS + Windows binaries, attaches them all to the GitHub release, publishes <code>@zkqes/cli</code> to npm, and bumps <code>Formula/zkqes.rb</code> in the <code>alik-eth/homebrew-zkqes</code> tap repo.</li></ol><h2 id="required-github-repo-secrets" tabindex="-1">Required GitHub repo secrets <a class="header-anchor" href="#required-github-repo-secrets" aria-label="Permalink to &quot;Required GitHub repo secrets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Secret</th><th>Purpose</th><th>Cost / setup</th></tr></thead><tbody><tr><td><code>NPM_TOKEN</code></td><td>publishes <code>@zkqes/cli</code> to the npm registry</td><td>free; create at npmjs.com → Access Tokens</td></tr><tr><td><code>APPLE_DEVELOPER_ID</code></td><td>the human-readable identity name for <code>codesign --sign</code> (e.g. <code>&quot;Developer ID Application: Acme LLC (ABCDEF1234)&quot;</code>)</td><td>$99/yr Apple Developer Program</td></tr><tr><td><code>APPLE_ID</code></td><td>the Apple ID email used for notarization</td><td>included in Developer Program</td></tr><tr><td><code>APPLE_APP_PASSWORD</code></td><td>an app-specific password for <code>notarytool</code></td><td>created at appleid.apple.com</td></tr><tr><td><code>APPLE_TEAM_ID</code></td><td>your 10-character team ID</td><td>included in Developer Program</td></tr><tr><td><code>WIN_PFX_BASE64</code></td><td>base64 of the Authenticode <code>.pfx</code> certificate</td><td>$200–400/yr from Sectigo, DigiCert, etc.</td></tr><tr><td><code>WIN_PFX_PASSWORD</code></td><td>password for the <code>.pfx</code></td><td>set when generating the cert</td></tr><tr><td><code>HOMEBREW_TAP_TOKEN</code></td><td>a fine-grained PAT that can push to <code>alik-eth/homebrew-zkqes</code></td><td>free; create at github.com/settings/tokens</td></tr></tbody></table><p>Without <code>APPLE_*</code> the macOS matrix legs will fail (Gatekeeper blocks unsigned binaries on macOS 14+). Without <code>WIN_PFX_*</code> the Windows leg fails (SmartScreen warns users on unsigned <code>.exe</code>s; the workflow does hard-fail rather than emit an unsigned binary).</p><p>If you need to ship an interim release without one of the platforms working, comment out that matrix entry rather than removing the secret gating — losing the gate later is harder to spot.</p><h2 id="external-resources" tabindex="-1">External resources <a class="header-anchor" href="#external-resources" aria-label="Permalink to &quot;External resources&quot;">​</a></h2><ul><li>Homebrew tap repo: must exist at <code>https://github.com/alik-eth/homebrew-zkqes</code> before the first release. The repo only needs a <code>Formula/zkqes.rb</code> file; the workflow&#39;s <code>update-tap</code> job rewrites the <code>version</code> and <code>sha256</code> lines on each release.</li><li>npm scope <code>@zkqes</code>: the <code>NPM_TOKEN</code> must have publish rights to the scope. First publish needs to be done manually with <code>--access public</code> flag set in <code>package.json</code> or via the workflow&#39;s <code>--access public</code> argument.</li><li>GitHub release: <code>softprops/action-gh-release@v2</code> creates the release on the first matrix step that runs and appends each subsequent binary.</li></ul><h2 id="homebrew-tap-setup-one-time" tabindex="-1">Homebrew tap setup (one-time) <a class="header-anchor" href="#homebrew-tap-setup-one-time" aria-label="Permalink to &quot;Homebrew tap setup (one-time)&quot;">​</a></h2><p>Before the first release, create the tap repo at <code>https://github.com/alik-eth/homebrew-zkqes</code>:</p><ol><li>Create the repo (private or public, Homebrew works either way; public is conventional). Initialize with a README.</li><li>Copy <code>docs/cli-release-homebrew/Formula/zkqes.rb</code> from this repo into <code>Formula/zkqes.rb</code> in the tap repo. Commit and push.</li><li>Provision the <code>HOMEBREW_TAP_TOKEN</code> secret in this repo&#39;s settings: a fine-grained PAT scoped to the tap repo with <code>Contents: read &amp; write</code>.</li></ol><p>After step 3, every <code>cli-v*</code> tag push to this repo runs the workflow&#39;s <code>update-tap</code> job, which clones the tap repo, rewrites the four <code>sha256</code> lines and the <code>version</code> line in <code>Formula/zkqes.rb</code>, and pushes a commit <code>zkqes cli-v&lt;X.Y.Z&gt;</code>. Users then <code>brew tap alik-eth/homebrew-zkqes &amp;&amp; brew install zkqes</code>.</p><p>The formula template in <code>docs/cli-release-homebrew/Formula/zkqes.rb</code> is load-bearing for the tap repo&#39;s initial state. If you change the binary file naming (e.g. add a new architecture, rename <code>zkqes-linux-x64</code>), update the template here AND the <code>update-tap</code> job&#39;s loop.</p><h2 id="local-dry-run" tabindex="-1">Local dry-run <a class="header-anchor" href="#local-dry-run" aria-label="Permalink to &quot;Local dry-run&quot;">​</a></h2><p>The workflow can&#39;t be run locally end-to-end because of the secrets, but the binary build step is exactly what <code>pnpm -F @zkqes/cli build:binaries</code> runs. Use <code>ZKQES_BUILD_TARGETS=linux-x64</code> to limit a local smoke-build to your host architecture.</p>',18)])])}const m=t(d,[["render",s]]);export{u as __pageData,m as default};
